const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.colors=[0xff6b6b,0xffd166,0x7bdff2,0xb2f7ef,0xcdb4db];this.nodes=[];this.score=0;this.ui=this.add.text(10,10,'Score:0');for(let i=0;i<36;i++){const x=40+(i%6)*70,y=80+((i/6)|0)*70,c=Phaser.Math.Between(0,4);const n=this.add.circle(x,y,24,this.colors[c]).setInteractive();n.c=c;n.on('pointerdown',()=>this.pick(n));this.nodes.push(n);}this.chain=[];this.r=this.input.keyboard.addKey('R');}pick(n){if(this.chain.includes(n))return;if(this.chain.length&&this.chain[this.chain.length-1].c!==n.c){this.chain=[];return;}this.chain.push(n);n.setScale(1.2);if(this.chain.length>=3){this.chain.forEach(k=>{k.c=Phaser.Math.Between(0,4);k.setFillStyle(this.colors[k.c]);k.setScale(1);});this.score+=this.chain.length*5;this.ui.setText('Score:'+this.score);this.chain=[];}}update(){if(this.r.isDown)this.scene.restart();}}new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,scene:[S]});